import React from 'react';
import { useState } from 'react';
import "./Signup.css";
import Navbar from './Navbar';
import { useNavigate  } from 'react-router-dom';
import axios from 'axios';


function SignUpPage() {
    // const navigate = useNavigate();
    // const LoginBtn = () => {
    //     navigate("/Main")
    //   }


    const navigate = useNavigate();
    const [formData, setFormData] = useState({
        firstname: '',
        lastname: '',
        email: '',
        password: '',
        confirmPassword: '',
    });

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setFormData({ ...formData, [name]: value });
    };

    
    const baseURL = 'http://localhost:5000'; // Define the baseURL

const handleSubmit = async (e) => {
    e.preventDefault();

    try {
        const response = await axios.post(`${baseURL}/api/register`, formData, {
            headers: {
                'Content-Type': 'application/json',
            },
        });

        if (response.status === 201) {
            // User registered successfully, navigate to the main page
            navigate('/Main');
        } else {
            // Handle errors here, e.g., display an error message to the user
            console.error('Registration failed');
        }
    } catch (error) {
        console.error(error);
    }
};




    return(<>

    <Navbar/>
    
    <form class="form" action='/Signup'  onSubmit={handleSubmit}>
    <p class="title">Register </p>
    <p class="message">Signup now and get full access to our app. </p>
        <div class="flex">
        <label>
            <input class="input" type="text" placeholder="" required="" name='firstname'/>
            <span>firstname</span>
        </label>

        <label>
            <input class="input" type="text" placeholder="" required="" name='lastname'/>
            <span>lastname</span>
        </label>
    </div>  
            
    <label>
        <input class="input" type="email" placeholder="" required="" name='email'/>
        <span>Email</span>
    </label> 
        
    <label>
        <input className="input" type="password" placeholder="" required="" name='password'/>
        <span>Password</span>
    </label>
    <label>
        <input className="input" type="password" placeholder="" required="" name='confirm password'/>
        <span>Confirm password</span>
    </label>
    <button class="submit" >Submit</button>
    {/* onClick={LoginBtn} */}
</form>
    
    
    </>);
}

export default SignUpPage;
